+    #[test]
+    fn test_simd_probabilities() {
+        let amps = vec![
+            Complex64::new(0.6, 0.0),
+            Complex64::new(0.0, 0.8),
+            Complex64::new(0.5, 0.5),
+            Complex64::new(0.3, 0.4),
