+                let phase = rates[i] * PI; // Map firing rate to phase
+                let arg = k as f64 * omega_0 * phase;
+                sum_real += arg.cos();
+                sum_imag += arg.sin();
+            }
+
+            ((sum_real / n as f64).powi(2) + (sum_imag / n as f64).powi(2)).sqrt()
+        }).collect()
+    }
+}
