+        let coupling_range = (0..n_coupling)
+            .map(|i| coupling_min + (coupling_max - coupling_min) * i as f64 / (n_coupling - 1) as f64)
+            .collect();
+
+        let results = vec![vec![false; n_coupling]; n_amp];
+
