+        // Coupling weights
+        let pfc_to_hc = Self::generate_coupling_weights(
+            config.pfc_neurons, config.hc_neurons, config.pfc_hc_coupling
+        );
+        let hc_to_pfc = pfc_to_hc.t().to_owned();
