+        let mut weights = Array2::zeros((n, n));
+        let mut rng = rand::thread_rng();
+
+        use rand::Rng;
+        for i in 0..n {
+            for j in 0..n {
+                if i != j && rng.gen::<f64>() < sparsity {
+                    // Asymmetric: W_ij != W_ji
+                    weights[[i, j]] = rng.gen_range(-strength..strength);
+                }
+            }
+        }
+
+        weights
+    }
