+/// Cosine similarity between vectors
+fn cosine_similarity(a: &Array1<f64>, b: &Array1<f64>) -> f64 {
+    let dot = a.dot(b);
+    let norm_a = a.dot(a).sqrt();
+    let norm_b = b.dot(b).sqrt();
+
