+/// Generate random points in d-dimensional space
+fn generate_random_points(n: usize, d: usize) -> Vec<Vec<f32>> {
+    let mut rng = rand::thread_rng();
+    (0..n)
+        .map(|_| (0..d).map(|_| rng.gen_range(0.0..1.0)).collect())
+        .collect()
